parameters.jsCode:
// Parse Gemini OCR output + map to QuickEnergy rechnungen schema
const item = $input.first();

let invoice;
try {
  const raw = item.json.candidates[0].content.parts[0].text;
  invoice = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  throw new Error('Gemini konnte keine Rechnungsdaten extrahieren: ' + e.message);
}

// Storno detection
const isStorno = invoice.is_storno || false;
if (isStorno && invoice.invoice_amount > 0) {
  invoice.invoice_amount = -Math.abs(invoice.invoice_amount);
  if (invoice.invoice_net_amount) invoice.invoice_net_amount = -Math.abs(invoice.invoice_net_amount);
  if (invoice.invoice_tax_amount) invoice.invoice_tax_amount = -Math.abs(invoice.invoice_tax_amount);
}

// Primary tax rate
let primaryTaxRate = invoice.invoice_tax_rate || 19;
if (Array.isArray(invoice.line_items) && invoice.line_items.length > 0) {
  const rates = [...new Set(invoice.line_items.map(li => li.tax_rate).filter(r => r != null))];
  if (rates.length > 0) primaryTaxRate = rates[0];
}

// Normalize date helper
function normalizeDate(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  if (s.includes('.')) {
    const [d, m, y] = s.split('.');
    if (y && m && d) return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`;
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const parsed = new Date(s);
  return isNaN(parsed.getTime()) ? null : parsed.toISOString().split('T')[0];
}

// Build storage URL from upload result
const uploadResult = $('Upload PDF to Supabase Storage').first().json;
const storageKey = uploadResult.Key || uploadResult.path || null;
const pdfUrl = storageKey
  ? `https://emrjxrtxlvyrwplglkzk.supabase.co/storage/v1/object/public/${storageKey}`
  : null;

return [{
  json: {
    rechnungsnr:    invoice.invoice_number || `IMPORT-${Date.now().toString(36).toUpperCase()}`,
    betrag:         invoice.invoice_amount || 0,
    ust_satz:       primaryTaxRate,
    faelligkeit:    normalizeDate(invoice.invoice_due_date),
    skonto_datum:   normalizeDate(invoice.skonto_datum),
    skonto_prozent: invoice.skonto_prozent || null,
    status:         'eingegangen',
    pdf_url:        pdfUrl,
    ocr_json:       invoice
  }
}];
